create table biz_consumer_decision
(
    decision_id       integer,
    respondent_id     integer,
    study_id          integer,
    decision_type     text,
    employment_status text,
    income_at_time    text,
    amount_usd        double precision,
    decision_date     text,
    reversed          text,
    confidence_score  text
);

create table biz_employment_wave
(
    wave_id           integer,
    study_id          integer,
    respondent_id     integer,
    wave_date         text,
    employment_status text,
    job_sector        text,
    weekly_hours      double precision,
    gross_monthly_usd double precision,
    job_satisfaction  text,
    financial_anxiety text
);

create table biz_market_sentiment
(
    sentiment_id     integer,
    study_id         integer,
    segment_label    text,
    period_start     text,
    period_end       text,
    n_respondents    integer,
    avg_confidence   double precision,
    avg_spend_intent double precision,
    avg_save_intent  double precision,
    dataset_id       integer
);

create table biz_response_item
(
    response_id   integer,
    item_index    integer,
    raw_answer    integer,
    numeric_score double precision
);

create table biz_study_dataset
(
    study_id     integer,
    dataset_id   integer,
    usage_role   text,
    rows_sampled integer
);

create table biz_study
(
    study_id      integer,
    title         text,
    research_type text,
    topic         text,
    start_date    text,
    end_date      text,
    target_n      integer,
    achieved_n    integer,
    status        text
);

create table biz_survey_response
(
    response_id     integer,
    study_id        integer,
    respondent_id   integer,
    instrument_id   integer,
    collected_at    text,
    channel         text,
    completion_secs text,
    is_complete     text
);

